$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 48
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0

while ($ELAPSED -lt $TIMEOUT) {
    # Strategy A: "Copilot's findings"
    $findings = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.body | test("Copilot.s findings")) | {id: .id, body: .body}' 2>$null | Select-Object -Last 1

    if (-not $findings) {
        # Strategy B: "Pull request overview"
        $findings = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.body | test("Pull request overview")) | {id: .id, body: .body}' 2>$null | Select-Object -Last 1
    }

    if (-not $findings) {
        # Strategy C: copilot-pull-request-reviewer bot
        $findings = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer")) | {id: .id, body: .body}' 2>$null | Select-Object -Last 1
    }

    if (-not $findings) {
        # Strategy D: Line-level comments from "Copilot"
        $findings = gh api "/repos/$REPO/pulls/$PR/comments" --jq '.[] | select(.user.login == "Copilot") | {id: .id, body: .body}' 2>$null | Select-Object -First 1
    }

    if ($findings) {
        Write-Host "FOUND review findings after $ELAPSED seconds:"
        Write-Host $findings
        break
    }

    Write-Host "Polling... $ELAPSED seconds elapsed"
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if (-not $findings) {
    Write-Host "TIMEOUT: No Copilot review found after $TIMEOUT seconds"
}

