arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$owner, $name = $REPO -split '/'

# Get thread IDs for both comments
$query = @"
query {
  repository(owner: "$owner", name: "$name") {
    pullRequest(number: 48) {
      reviewThreads(first: 100) {
        nodes {
          id
          isResolved
          comments(first: 1) { nodes { databaseId } }
        }
      }
    }
  }
}
"@

$result = gh api graphql -f query="$query" 2>&1
$result

$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$owner, $name = $REPO -split '/'

# Get thread IDs for both comments
$query = @"
query {
  repository(owner: "$owner", name: "$name") {
    pullRequest(number: 48) {
      reviewThreads(first: 100) {
        nodes {
          id
          isResolved
          comments(first: 1) { nodes { databaseId } }
        }
      }
    }
  }
}
"@

$result = gh api graphql -f query="$query" 2>&1
$result

$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 48
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0
# We already saw review id 4729599914 in round 1 - need a new one
$KNOWN_REVIEW_ID = 4729599914

while ($ELAPSED -lt $TIMEOUT) {
    # Get all reviews and filter for new Copilot reviews
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq ".[] | select(.body | test(`"Pull request overview|Copilot.s findings`")) | {id: .id, body: .body}" 2>$null

    if ($reviews) {
        # Check if there's a new review (different from round 1)
        $newReview = $reviews | ForEach-Object {
            $parsed = $_ | ConvertFrom-Json -ErrorAction SilentlyContinue
            if ($parsed -and $parsed.id -ne $KNOWN_REVIEW_ID) { $_ }
        }
        if ($newReview) {
            Write-Host "FOUND new review after $ELAPSED seconds:"
            Write-Host $newReview
            break
        }
    }

    # Also check for new line-level comments from Copilot (that are unresolved)
    $threads = gh api graphql -f query="
    query {
      repository(owner: `"edburns`", name: `"Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk`") {
        pullRequest(number: $PR) {
          reviewThreads(first: 100) {
            nodes {
              isResolved
              comments(first: 1) { nodes { databaseId author { login } } }
            }
          }
        }
      }
    }" --jq '.data.repository.pullRequest.reviewThreads.nodes[] | select(.isResolved == false) | select(.comments.nodes[0].author.login | test("copilot-pull-request-reviewer|Copilot")) | .comments.nodes[0].databaseId' 2>$null

    if ($threads) {
        Write-Host "FOUND unresolved Copilot threads after $ELAPSED seconds:"
        Write-Host $threads
        break
    }

    Write-Host "Polling round 2... $ELAPSED seconds elapsed"
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if ($ELAPSED -ge $TIMEOUT -and -not $newReview -and -not $threads) {
    Write-Host "TIMEOUT: No new Copilot review found — assuming 0 comments this round"
}

