async openDetail(queryId) {
    this.selectedQueryId = queryId;
    this.detailAgent = null;
    // Snapshot existing WS events so we can merge after fetch
    const preFetchEvents = [...(this.queryEvents[queryId] || [])];
    try {
        const response = await fetch(`/api/agent/${queryId}`);
        // Discard stale response if user navigated away during fetch
        if (this.selectedQueryId !== queryId) return;
        if (!response.ok) {
            this.detailAgent = { queryId, queryText: "", phase: "Unknown", intent: "", reportText: "", events: [] };
            this.queryEvents[queryId] = [];
            return;
        }
        const data = await response.json();
        if (this.selectedQueryId !== queryId) return;
        this.detailAgent = data;
        const serverEvents = data.events || [];
        // Merge: keep server history, then append any WS events that arrived during the fetch
        const serverTimestamps = new Set(serverEvents.map(e => e.timestamp));
        const newWsEvents = (this.queryEvents[queryId] || [])
            .filter(e => !preFetchEvents.includes(e) && !serverTimestamps.has(e.timestamp));
        this.queryEvents[queryId] = [...serverEvents, ...newWsEvents];
    } catch (_) {
        if (this.selectedQueryId !== queryId) return;
        this.detailAgent = { queryId, queryText: "", phase: "Unknown", intent: "", reportText: "", events: [] };
        this.queryEvents[queryId] = [];
    }
},

