arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 48
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0

$knownReviewIds = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '[.[] | select(.body | test("Pull request overview|Copilot.s findings")) | .id]' 2>$null | ConvertFrom-Json

while ($ELAPSED -lt $TIMEOUT) {
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL

    $currentIds = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '[.[] | select(.body | test("Pull request overview|Copilot.s findings")) | .id]' 2>$null | ConvertFrom-Json
    $newIds = $currentIds | Where-Object { $_ -notin $knownReviewIds }

    if ($newIds) {
        $newId = $newIds[0]
        $body = gh api "/repos/$REPO/pulls/$PR/reviews/$newId" --jq '.body' 2>$null
        if ($body -match 'Comments generated:\s*(\d+)') {
            Write-Host "Comments generated: $($Matches[1]) after $ELAPSED seconds"
            if ([int]$Matches[1] -eq 0) { Write-Host "CLEAN REVIEW!" }
        }
        break
    }

    $unresolvedCount = gh api graphql -f query='query { repository(owner: "edburns", name: "Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk") { pullRequest(number: 48) { reviewThreads(first: 100) { nodes { isResolved comments(first: 1) { nodes { author { login } } } } } } } }' --jq '[.data.repository.pullRequest.reviewThreads.nodes[] | select(.isResolved == false) | select(.comments.nodes[0].author.login | test("copilot-pull-request-reviewer|Copilot"))] | length' 2>$null

    if ($unresolvedCount -and [int]$unresolvedCount -gt 0) {
        Write-Host "FOUND $unresolvedCount unresolved threads after $ELAPSED seconds"
        break
    }

    Write-Host "Polling round 8... $ELAPSED seconds elapsed"
}

if ($ELAPSED -ge $TIMEOUT -and -not $newIds) {
    Write-Host "TIMEOUT: No new findings — assuming 0 comments"
}

